  const [salesSortDir, setSalesSortDir] = useState<'asc' | 'desc'>('desc');
  const [salesSourceFilter, setSalesSourceFilter] = useState('all');
  const [isManualSaleDialogOpen, setIsManualSaleDialogOpen] = useState(false);
