  // Sheet sync states for Edit Product
  const [sheetSyncAttrs, setSheetSyncAttrs] = useState({
    name: false,
    price: false,
    quantity: false,
    images: false,
    description: false,
  });
  const [isSyncingFromSheet, setIsSyncingFromSheet] = useState(false);

  const handleSyncFromSheet = async (productId: string) => {
    const selectedKeys = Object.entries(sheetSyncAttrs)
      .filter(([_, selected]) => selected)
      .map(([key]) => key);
    
    if (selectedKeys.length === 0) {
      toast.error('Please select at least one attribute to sync');
      return;
    }
    
    setIsSyncingFromSheet(true);
    try {
      for (const columnKey of selectedKeys) {
                        const res = await fetch('/api/sheet-sync/bulk', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ columnKey, productIds: [productId] }),
        });
        if (!res.ok) {
          const err = await res.json();
          throw new Error(err.error || `Failed to sync ${columnKey}`);
        }
      }
      queryClient.invalidateQueries({ queryKey: ['products'] });
      toast.success('Synced from sheet successfully');
      setSheetSyncAttrs({ name: false, price: false, quantity: false, images: false, description: false });
    } catch (error: any) {
      toast.error(error.message || 'Failed to sync from sheet');
    } finally {
      setIsSyncingFromSheet(false);
    }
  };


  const hasPriceChanges = useMemo(() => {
    return Object.keys(editedPrices).some(productId => {
      const product = productList.find(p => p.id === productId);
      if (!product) return false;
      return editedPrices[productId] !== String(product.price);
    });
  }, [editedPrices, productList]);

  const saveAllPrices = async () => {
    setIsSavingPrices(true);
    try {
      const updates: Promise<any>[] = [];
      for (const [productId, priceValue] of Object.entries(editedPrices)) {
        const product = productList.find(p => p.id === productId);
        if (!product) continue;
        const newPrice = parseFloat(priceValue) || 0;
        if (String(newPrice) !== String(product.price)) {
          updates.push(
            fetch(`/api/products/${productId}`, {
              method: 'PATCH',
              headers: { 'Content-Type': 'application/json' },
              credentials: 'include',
              body: JSON.stringify({ price: newPrice }),
            })
          );
        }
      }
      
      if (updates.length === 0) {
        toast.info('No price changes to save');
        setIsSavingPrices(false);
        return;
      }
      
      const results = await Promise.all(updates);
      const failedCount = results.filter(r => !r.ok).length;
      
      queryClient.invalidateQueries({ queryKey: ['products'] });
      setEditedPrices({});
      
      if (failedCount > 0) {
        toast.error(`${failedCount} price update(s) failed`);
      } else {
        toast.success('Price changes saved');
      }
    } catch (error) {
      console.error('Save prices error:', error);
      toast.error('Failed to save price changes');
    } finally {
      setIsSavingPrices(false);
    }
  };

  const saveSinglePrice = async (productId: string) => {
    const priceValue = editedPrices[productId];
    if (priceValue === undefined) return;
    const product = productList.find(p => p.id === productId);
    if (!product) return;
    const newPrice = parseFloat(priceValue) || 0;
    if (String(newPrice) === String(product.price)) {
      setEditedPrices(prev => {
        const updated = { ...prev };
        delete updated[productId];
        return updated;
      });
      return;
    }
    try {
                        const res = await fetch(`/api/products/${productId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ price: newPrice }),
      });
      if (res.ok) {
        queryClient.invalidateQueries({ queryKey: ['products'] });
        setEditedPrices(prev => {
          const updated = { ...prev };
          delete updated[productId];
          return updated;
        });
        toast.success('Price saved');
      } else {
        toast.error('Failed to save price');
      }
    } catch (error) {
      toast.error('Failed to save price');
    }
  };

  const saveSingleCostPrice = async (productId: string) => {
    const costValue = editedCostPrices[productId];
    if (costValue === undefined) return;
    const product = productList.find(p => p.id === productId);
    if (!product) return;
    const newCost = costValue === '' ? null : (parseFloat(costValue) || 0);
    const currentCost = product.costPrice ? parseFloat(String(product.costPrice)) : null;
    if (newCost === currentCost || (newCost === 0 && currentCost === null)) {
      setEditedCostPrices(prev => {
        const updated = { ...prev };
        delete updated[productId];
        return updated;
      });
      return;
    }
    try {
                        const res = await fetch(`/api/products/${productId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ costPrice: newCost }),
      });
      if (res.ok) {
        queryClient.invalidateQueries({ queryKey: ['products'] });
        setEditedCostPrices(prev => {
          const updated = { ...prev };
          delete updated[productId];
          return updated;
        });
        toast.success('Cost saved');
      } else {
        toast.error('Failed to save cost');
      }
    } catch (error) {
      toast.error('Failed to save cost');
    }
  };

  const saveSingleRow = async (productId: string) => {
    const rowValue = editedRows[productId];
    if (rowValue === undefined) return;
    const product = productList.find(p => p.id === productId);
    if (!product) return;
    const newRow = rowValue === '' ? null : (parseInt(rowValue) || null);
    if (newRow === product.sheetRow) {
      setEditedRows(prev => {
        const updated = { ...prev };
        delete updated[productId];
        return updated;
      });
      return;
    }
    try {
                        const res = await fetch(`/api/products/${productId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ sheetRow: newRow }),
      });
      if (res.ok) {
        queryClient.invalidateQueries({ queryKey: ['products'] });
        setEditedRows(prev => {
          const updated = { ...prev };
          delete updated[productId];
          return updated;
        });
        toast.success('Row saved');
      } else {
        toast.error('Failed to save row');
      }
    } catch (error) {
      toast.error('Failed to save row');
    }
  };

  const handleBatchRowShift = async () => {
    const amount = parseInt(batchRowShiftAmount) || 0;
    if (amount <= 0) {
      toast.error('Enter a valid amount');
      return;
    }
    const delta = batchRowShiftDirection === 'increase' ? amount : -amount;
    let successCount = 0;
    let errorCount = 0;
    for (const productId of selectedProducts) {
      const product = productList.find(p => p.id === productId);
      if (!product || product.sheetRow === null) continue;
      const newRow = product.sheetRow + delta;
      if (newRow < 1) continue;
      try {
                        const res = await fetch(`/api/products/${productId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ sheetRow: newRow }),
        });
        if (res.ok) successCount++;
        else errorCount++;
      } catch {
        errorCount++;
      }
    }
    queryClient.invalidateQueries({ queryKey: ['products'] });
    setIsBatchRowShiftDialogOpen(false);
    setBatchRowShiftAmount('1');
    if (successCount > 0) toast.success(`Shifted ${successCount} row(s)`);
    if (errorCount > 0) toast.error(`Failed to shift ${errorCount} row(s)`);
  };

