  const handleCancelImport = () => {
    importCancelledRef.current = true;
    setIsImporting(false);
  };

  const handleBatchImport = async () => {
    const urls = importUrls.split('\n').map(u => u.trim()).filter(u => u.length > 0);
    if (urls.length === 0) return;
    
    setIsImporting(true);
    importCancelledRef.current = false;
    setImportError('');
    setBatchImportProgress({ current: 0, total: urls.length, created: 0, failed: [] });
    
    const failed: { url: string; reason: string }[] = [];
    const importedProducts: typeof batchProducts = [];
    
    for (let i = 0; i < urls.length; i++) {
      // Check if import was cancelled
      if (importCancelledRef.current) {
        setImportError('Import cancelled');
        break;
      }
      
      const url = urls[i];
      setBatchImportProgress({ current: i + 1, total: urls.length, created: importedProducts.length, failed });
      
      try {
        // Import product data from URL
        const importRes = await fetch('/api/products/import', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ url }),
        });
        
        if (!importRes.ok) {
          const errorData = await importRes.json().catch(() => ({}));
          failed.push({ url, reason: errorData.error || 'Failed to fetch URL' });
          continue;
        }
        
        const imported = await importRes.json();
        
        // Allow products with just images (image-only URLs get AI-generated titles)
        if (!imported.images?.length) {
          failed.push({ url, reason: 'No product images found' });
          continue;
        }
        
        const detectedCategory = detectCategoryFromTitle(imported.title || '');
        const descriptionText = imported.description 
          ? (Array.isArray(imported.description) ? imported.description.join('\n') : String(imported.description))
          : '';
        
        // Price must be string
        const priceValue = imported.price != null ? String(imported.price) : '0';
        
        // Add to batch for review instead of saving directly
        importedProducts.push({
          name: imported.title || '',
          description: descriptionText,
          price: priceValue,
          category: SKU_CATEGORIES[detectedCategory] || 'Electronics',
          images: imported.images,
          imageUrl: '',
          skuCategory: detectedCategory || 'EL',
          skuSize: 'S' as SkuSizeCode,
          colors: [],
          condition: 'New' as ProductCondition,
          quantity: 0,
        });
      } catch (error) {
        failed.push({ url, reason: error instanceof Error ? error.message : 'Unknown error' });
      }
    }
    
    setBatchImportProgress({ current: urls.length, total: urls.length, created: importedProducts.length, failed });
    
    if (importedProducts.length > 0) {
      setBatchProducts(prev => [...prev, ...importedProducts]);
      setImportUrls('');
    }
    
    if (failed.length > 0) {
      setImportError(`${failed.length} URL(s) failed to import`);
    }
    
    setIsImporting(false);
  };

  const [importFeedback, setImportFeedback] = useState<{ created: number; queued: number; merged?: number; warnings?: string[] } | null>(null);
  
  const handleImageUpload = async (file: File): Promise<string | null> => {
    setIsUploadingImage(true);
    try {
      // Request presigned URL
      const urlRes = await fetch('/api/uploads/request-url', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          name: file.name,
          size: file.size,
          contentType: file.type,
        }),
      });
      
      if (!urlRes.ok) throw new Error('Failed to get upload URL');
      
      const { uploadURL, objectPath } = await urlRes.json();
      
      // Upload file to presigned URL
      const uploadRes = await fetch(uploadURL, {
        method: 'PUT',
        body: file,
        headers: { 'Content-Type': file.type },
      });
      
      if (!uploadRes.ok) throw new Error('Failed to upload image');
      
      // Return the object path that can be used to serve the image
      // objectPath is like "/objects/uploads/uuid" so we prefix with "/api"
      const imageUrl = `/api${objectPath}`;
      console.log('Image uploaded successfully:', imageUrl);
      return imageUrl;
    } catch (error) {
      console.error('Image upload failed:', error);
      toast.error('Failed to upload image');
      return null;
    } finally {
      setIsUploadingImage(false);
    }
  };
  
