  const handleAddProduct = async () => {
    if (newProduct.images.length === 0) {
      return;
    }
    
    // Convert description to string for templates API
    const descriptionString = newProduct.description;
    
    try {
      // Use new templates API with automatic duplicate detection
                        const res = await fetch('/api/templates', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          name: newProduct.name,
          description: descriptionString,
          price: (parseFloat(newProduct.price) || 0).toString(),
          category: newProduct.category,
          images: newProduct.images,
          colors: newProduct.colors.length > 0 ? newProduct.colors : undefined,
          condition: newProduct.condition?.toLowerCase() || 'new',
        }),
      });
      
      if (res.ok) {
        const result = await res.json();
        queryClient.invalidateQueries({ queryKey: ['templates'] });
        queryClient.invalidateQueries({ queryKey: ['batches'] });
        queryClient.invalidateQueries({ queryKey: ['products'] });
        queryClient.invalidateQueries({ queryKey: ['duplicates', 'pending'] });
        setProductSequence(prev => prev + 1);
        setNewProduct({ name: '', description: '', price: '', category: '', images: [], imageUrl: '', selectedNodes: [], initialStock: '0', skuCategory: '', skuSize: 'S', colors: [], condition: 'New' });
        setIsAddDialogOpen(false);
        
        // Show feedback based on action type
        if (result.action === 'created_with_warning') {
          setImportFeedback({ created: 1, queued: 0, warnings: [`Similar to existing template: ${result.potentialDuplicate?.name}`] });
        } else if (result.action === 'merged') {
          setImportFeedback({ created: 0, queued: 0, merged: 1, warnings: [`Merged with existing template: ${result.mergedWith?.productCode}`] });
        } else {
          setImportFeedback({ created: 1, queued: 0 });
        }
      } else {
        const error = await res.json().catch(() => ({ error: 'Unknown error' }));
        setImportFeedback({ created: 0, queued: 0, warnings: [`Failed to import: ${error.error || 'Unknown error'}`] });
      }
    } catch (error) {
      console.error('Failed to add product:', error);
      setImportFeedback({ created: 0, queued: 0, warnings: ['Failed to import product. Please try again.'] });
    }
  };
  
  const handleAddBatchProducts = async () => {
    if (batchProducts.length === 0) {
      return;
    }
    
    try {
      const validProducts = batchProducts.filter(bp => bp.images.length > 0 && bp.name.trim());
      let created = 0;
      let queued = 0;
      
      const warnings: string[] = [];
      let merged = 0;
      
      for (let index = 0; index < validProducts.length; index++) {
        const bp = validProducts[index];
        
        // Use the new templates API which handles duplicate detection automatically
                        const res = await fetch('/api/templates', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({
            name: bp.name,
            description: normalizeDescriptionForStorage(bp.description),
            price: (parseFloat(bp.price) || 0).toString(),
            category: bp.category,
            images: bp.images,
            colors: bp.colors.length > 0 ? bp.colors : undefined,
            condition: bp.condition || 'new',
          }),
        });
        
        if (res.ok) {
          const result = await res.json();
          if (result.action === 'created_with_warning') {
            created++;
            warnings.push(`"${bp.name}" similar to: ${result.potentialDuplicate?.name}`);
          } else if (result.action === 'merged') {
            merged++;
            warnings.push(`"${bp.name}" merged with: ${result.mergedWith?.productCode}`);
          } else {
            created++;
          }
        } else {
          const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
          warnings.push(`"${bp.name}" failed: ${errorData.error || 'Unknown error'}`);
        }
      }
      
      // Invalidate templates and products queries
      queryClient.invalidateQueries({ queryKey: ['templates'] });
      queryClient.invalidateQueries({ queryKey: ['batches'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['duplicates', 'pending'] });
      setProductSequence(prev => prev + validProducts.length);
      setBatchProducts([]);
      setBatchImportProgress(null);
      setNewProduct({ name: '', description: '', price: '', category: '', images: [], imageUrl: '', selectedNodes: [], initialStock: '0', skuCategory: '', skuSize: 'S', colors: [], condition: 'New' });
      setIsAddDialogOpen(false);
      
      // Show feedback about import results
      setImportFeedback({ created, queued: 0, merged: merged > 0 ? merged : undefined, warnings: warnings.length > 0 ? warnings : undefined });
    } catch (error) {
      console.error('Failed to add batch products:', error);
      setImportFeedback({ created: 0, queued: 0, warnings: ['Failed to import products. Please try again.'] });
    }
  };
  
