  const processPlaceholders = (text: string, product: { price: string | number }) => {
    const price = typeof product.price === 'string' ? parseFloat(product.price) : product.price;
    
    let result = text.replace(/\[price\]/gi, price.toFixed(2));
    
    result = result.replace(/\[price\s*x\s*([\d.]+)\]/gi, (match, multiplier) => {
      const mult = parseFloat(multiplier);
      if (isNaN(mult)) return match;
      return (price * mult).toFixed(2);
    });
    
    return result;
  };

  const handleExportListings = async () => {
    if (!exportIncludeTitle && !exportIncludeDescription && !exportIncludeAdditional && !exportIncludeTags) {
      toast.error('Please select at least one content option to export');
      return;
    }
    
    setIsExporting(true);
    try {
      const selectedProds = productList.filter(p => selectedProducts.includes(p.id));
      
      if (selectedProds.length === 0) {
        toast.error('No products selected');
        setIsExporting(false);
        return;
      }
      
      let productTags: Record<string, string[]> = { ...generatedTags };
      
      if (exportIncludeTags) {
        const productsNeedingTags = selectedProds.filter(p => !productTags[p.id] || productTags[p.id].length < exportTagCount);
        if (productsNeedingTags.length > 0) {
          setIsGeneratingTags(true);
          try {
            const response = await fetch('/api/products/generate-tags', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              credentials: 'include',
              body: JSON.stringify({
                products: productsNeedingTags.map(p => ({
                  id: p.id,
                  name: p.name,
                  category: p.category,
                  description: p.description,
                })),
                tagCount: exportTagCount,
              }),
            });
            if (response.ok) {
              const data = await response.json();
              productTags = { ...productTags, ...data.tags };
              setGeneratedTags(productTags);
            }
          } catch (err) {
            console.error('Error generating tags:', err);
          }
          setIsGeneratingTags(false);
        }
      }
      
      const children: Paragraph[] = [];
      
      const renderTitle = (product: any) => {
        const prependWithSpace = exportTitlePrepend ? `${exportTitlePrepend} ` : '';
        const titleText = `${prependWithSpace}${product.name}${exportTitleAppend}`;
        children.push(
          new Paragraph({
            children: [
              new TextRun({
                text: titleText,
                bold: true,
                size: 32,
              }),
            ],
            heading: HeadingLevel.HEADING_1,
            spacing: { after: 200 },
          })
        );
      };
      
      const renderAdditional = (product: any) => {
        const processedContent = processPlaceholders(exportAdditionalContent, product);
        const lines = processedContent.split('\n');
        lines.forEach((line, lineIndex) => {
          children.push(
            new Paragraph({
              children: [
                new TextRun({
                  text: line,
                  size: 22,
                }),
              ],
              spacing: { after: lineIndex === lines.length - 1 ? 300 : 100 },
            })
          );
        });
      };
      
      const renderDescription = (product: any) => {
        const descriptionPoints = getDescriptionPoints(product.description);
        
        if (exportDescriptionPrepend) {
          children.push(
            new Paragraph({
              children: [new TextRun({ text: exportDescriptionPrepend, size: 24 })],
              spacing: { after: 200 },
            })
          );
        }
        
        descriptionPoints.forEach((point, pointIndex) => {
          children.push(
            new Paragraph({
              children: [
                new TextRun({
                  text: point,
                  size: 24,
                }),
              ],
              spacing: { after: 200 },
            })
          );
          if (pointIndex < descriptionPoints.length - 1) {
            children.push(
              new Paragraph({
                children: [new TextRun({ text: '', size: 24 })],
                spacing: { after: 200 },
              })
            );
          }
        });
        
        if (exportDescriptionAppend) {
          children.push(
            new Paragraph({
              children: [new TextRun({ text: '', size: 24 })],
              spacing: { after: 200 },
            })
          );
          children.push(
            new Paragraph({
              children: [new TextRun({ text: exportDescriptionAppend, size: 24 })],
              spacing: { after: 200 },
            })
          );
        }
      };
      
      const renderTags = (product: any) => {
        const tags = productTags[product.id]?.slice(0, exportTagCount) || [];
        if (tags.length > 0) {
          children.push(
            new Paragraph({
              children: [
                new TextRun({
                  text: 'Tags: ',
                  bold: true,
                  size: 20,
                  color: '666666',
                }),
                new TextRun({
                  text: tags.join(', '),
                  size: 20,
                  color: '666666',
                }),
              ],
              spacing: { after: 200 },
            })
          );
        }
      };
      
      const renderCode = (product: any) => {
        children.push(
          new Paragraph({
            children: [
              new TextRun({
                text: product.productCode || `ID: ${product.id.slice(0, 8)}`,
                bold: true,
                size: 20,
                font: 'Courier New',
                color: '333333',
              }),
            ],
            spacing: { after: 300 },
          })
        );
      };
      
      selectedProds.forEach((product, index) => {
        exportSectionOrder.forEach((section) => {
          switch (section) {
            case 'title':
              if (exportIncludeTitle) renderTitle(product);
              break;
            case 'description':
              if (exportIncludeDescription && product.description) renderDescription(product);
              break;
            case 'additional':
              if (exportIncludeAdditional && exportAdditionalContent) renderAdditional(product);
              break;
            case 'tags':
              if (exportIncludeTags) renderTags(product);
              break;
            case 'code':
              renderCode(product);
              break;
          }
        });
        
        if (index < selectedProds.length - 1) {
          children.push(
            new Paragraph({
              children: [new PageBreak()],
            })
          );
        }
      });
      
      const doc = new Document({
        sections: [{
          properties: {},
          children,
        }],
      });
      
      const blob = await Packer.toBlob(doc);
      saveAs(blob, `product-listings-${new Date().toISOString().split('T')[0]}.docx`);
      toast.success(`Exported ${selectedProds.length} product listings`);
      setIsExportDialogOpen(false);
    } catch (error: any) {
      console.error('Export error:', error);
      toast.error('Export failed: ' + error.message);
    }
    setIsExporting(false);
  };

