  const handleAssignProductsToNode = async () => {
    if (!assignToNodeId || selectedProducts.length === 0) return;
    
    try {
      const productsWithQuantity = selectedProducts.filter(productId => {
        const qty = parseInt(assignQuantities[productId]) || 0;
        return qty > 0;
      });
      
      const skippedCount = selectedProducts.length - productsWithQuantity.length;
      
      if (productsWithQuantity.length === 0) {
        toast.warning('No products to add', {
          description: 'All selected products have zero quantity. Set a quantity greater than zero to add them.'
        });
        return;
      }
      
      for (const productId of productsWithQuantity) {
        const qty = parseInt(assignQuantities[productId]) || 0;
        await fetch('/api/inventory', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            productId,
            nodeId: assignToNodeId,
            quantity: qty,
          }),
        });
      }
      
      // Invalidate all relevant queries to refresh data across the app
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['templates'] });
      queryClient.invalidateQueries({ queryKey: ['batches'] });
      
      // Refetch nodes to update inventory counts in node management
      fetch('/api/nodes')
        .then(res => res.json())
        .then(nodes => setNodeList(nodes))
        .catch(err => console.error('Failed to refresh nodes:', err));
      
      
      setSelectedProducts([]);
      setIsAssignToNodeDialogOpen(false);
      setAssignToNodeId('');
      setAssignQuantities({});
      
      if (skippedCount > 0) {
        toast.success(`Added ${productsWithQuantity.length} products to node`, {
          description: `${skippedCount} product${skippedCount > 1 ? 's' : ''} with zero quantity ${skippedCount > 1 ? 'were' : 'was'} skipped.`
        });
      } else {
        toast.success(`Added ${productsWithQuantity.length} products to node`);
      }
    } catch (error) {
      console.error('Failed to assign products to node:', error);
      toast.error('Failed to add products to node');
    }
  };

  const initializeAssignQuantities = (useProductQty: boolean = true) => {
    const quantities: Record<string, string> = {};
    selectedProducts.forEach(id => {
      const product = productList.find(p => p.id === id);
      if (useProductQty && product) {
        // Use sheetQuantity if available, otherwise use current total inventory, fallback to 1
        const sheetQty = product.sheetQuantity || 0;
        const inventoryQty = product.inventory?.reduce((sum, inv) => sum + inv.quantity, 0) || 0;
        quantities[id] = String(sheetQty > 0 ? sheetQty : (inventoryQty > 0 ? inventoryQty : 1));
      } else {
        quantities[id] = '1';
      }
    });
    setAssignQuantities(quantities);
  };

  const handleUpdateNode = async (updatedNode: Node) => {
    try {
      let handoffTiers = updatedNode.handoffTiers;
      if (handoffTiers && Array.isArray(handoffTiers)) {
        handoffTiers = handoffTiers
          .map(t => ({ minQty: Math.max(1, t.minQty), fee: Math.max(0, t.fee), ...(t.applyAbove ? { applyAbove: true } : {}) }))
          .sort((a, b) => a.minQty - b.minQty);
        if (handoffTiers.some((t, i, arr) => i > 0 && t.minQty === arr[i-1].minQty)) {
          toast.error('Tier quantities must be unique');
          return;
        }
        if (handoffTiers.some(t => isNaN(t.minQty) || isNaN(t.fee))) {
          toast.error('Invalid tier values');
          return;
        }
      }
      
                        const res = await fetch(`/api/nodes/${updatedNode.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: updatedNode.name,
          address: updatedNode.address,
          city: updatedNode.city,
          servingCityId: updatedNode.servingCityId,
          latitude: updatedNode.latitude,
          longitude: updatedNode.longitude,
          pickupInstructions: updatedNode.pickupInstructions,
          status: updatedNode.status,
          availabilityNoticeHours: updatedNode.availabilityNoticeHours,
          minimumAvailabilityHours: updatedNode.minimumAvailabilityHours,
          isAdminNode: updatedNode.isAdminNode,
          handoffTiers: handoffTiers,
          monthlyFee: updatedNode.monthlyFee,
          earningsPerHandoff: updatedNode.earningsPerHandoff,
          kitCount: updatedNode.kitCount,
          kitFee: updatedNode.kitFee,
        }),
      });
      if (res.ok) {
        const saved = await res.json();
        setNodeList(nodeList.map(n => n.id === saved.id ? saved : n));
        queryClient.invalidateQueries({ queryKey: ['all-nodes'] });
        toast.success('Node settings saved');
      } else {
        const err = await res.json().catch(() => ({ error: 'Failed to save node' }));
        toast.error(err.error || 'Failed to save node');
      }
    } catch (error) {
      console.error('Failed to update node:', error);
      toast.error('Failed to update node');
    }
  };

