  const handleBulkPaste = () => {
    if (!bulkPasteText.trim()) return;
    
    const lines = bulkPasteText.split('\n').filter(l => l.trim());
    const codeRegex = /^(GM[\s\-]*[\w\-]+)\s*x\s*(\d+)/i;
    
    let added = 0;
    let failed = 0;
    const failedCodes: string[] = [];
    const newItems = [...newNodeKit.items];
    
    for (const line of lines) {
      const match = line.trim().match(codeRegex);
      if (!match) {
        failed++;
        failedCodes.push(line.trim());
        continue;
      }
      
      const rawCode = match[1].trim();
      const quantity = parseInt(match[2]) || 1;
      
      const normalizedCode = rawCode.replace(/[\s\-]+/g, '').toUpperCase();
      
      const product = productList.find(p => {
        if (!p.productCode) return false;
        const pCode = p.productCode.replace(/[\s\-]+/g, '').toUpperCase();
        return pCode === normalizedCode;
      });
      
      if (!product) {
        failed++;
        failedCodes.push(`${rawCode} (not found)`);
        continue;
      }
      
      const existingIdx = newItems.findIndex(i => i.productId === product.id);
      if (existingIdx >= 0) {
        newItems[existingIdx] = { ...newItems[existingIdx], quantity: newItems[existingIdx].quantity + quantity };
      } else {
        newItems.push({ productId: product.id, quantity });
      }
      added++;
    }
    
    setNewNodeKit({ ...newNodeKit, items: newItems });
    setBulkPasteResult({ added, failed, total: lines.length, failedCodes });
    setBulkPasteText('');
  };

  const handleNodeCrateBulkPaste = async (assignmentId: string) => {
    if (!nodeCrateBulkPasteText.trim()) return;
    
    const nka = nodeKitAssignmentList.find(a => a.id === assignmentId);
    const crate = nka ? nodeKitList.find(k => k.id === nka.crateId) : null;
    if (!nka || !crate) return;
    
    setNodeQuantityWarningAcknowledged(prev => new Set(prev).add(assignmentId));
    
    const lines = nodeCrateBulkPasteText.split('\n').filter(l => l.trim());
    const codeRegex = /^(GM[\s\-]*[\w\-]+)\s*x\s*(\d+)/i;
    
    let updated = 0;
    let failed = 0;
    const failedCodes: string[] = [];
    
    const updates: { productId: string; quantity: number; originalQuantity: number }[] = [];
    
    for (const line of lines) {
      const match = line.trim().match(codeRegex);
      if (!match) {
        failed++;
        failedCodes.push(line.trim());
        continue;
      }
      
      const rawCode = match[1].trim();
      const quantity = parseInt(match[2]) || 0;
      const normalizedCode = rawCode.replace(/[\s\-]+/g, '').toUpperCase();
      
      const crateItem = ((crate as any).rawItems || crate.items).find((item: any) => {
        const code = item.productCode?.replace(/[\s\-]+/g, '').toUpperCase();
        return code === normalizedCode;
      });
      
      if (!crateItem) {
        failed++;
        failedCodes.push(`${rawCode} (not in crate)`);
        continue;
      }
      
      updates.push({ productId: crateItem.productId, quantity, originalQuantity: crateItem.quantity });
    }
    
    for (const update of updates) {
      try {
        const response = await fetch(`/api/crate-assignments/${assignmentId}/quantity-override`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ productId: update.productId, quantity: update.quantity, originalQuantity: update.originalQuantity }),
        });
        if (response.ok) {
          updated++;
        } else {
          failed++;
          failedCodes.push(`${update.productId} (server error)`);
        }
      } catch (error) {
        failed++;
        failedCodes.push(`${update.productId} (network error)`);
      }
    }
    
    queryClient.invalidateQueries({ queryKey: ['crate-assignments'] });
    if (updated > 0) {
      toast.success(`Updated ${updated} item${updated !== 1 ? 's' : ''}`);
    }
    
    setNodeCrateBulkPasteResult({ updated, failed, total: lines.length, failedCodes });
    setNodeCrateBulkPasteText('');
  };

