  const handleMergeCrates = async () => {
    if (selectedCrates.length < 2 || !mergeToCrateId) return;
    
    setIsMerging(true);
    try {
      const targetCrate = nodeKitList.find(c => c.id === mergeToCrateId);
      if (!targetCrate) throw new Error('Target crate not found');
      
      const sourceCrates = nodeKitList.filter(c => selectedCrates.includes(c.id) && c.id !== mergeToCrateId);
      
      const mergedItems: { productId: string; quantity: number; productName: string }[] = [...targetCrate.items];
      
      for (const sourceCrate of sourceCrates) {
        for (const item of sourceCrate.items) {
          const existing = mergedItems.find(i => i.productId === item.productId);
          if (existing) {
            existing.quantity += item.quantity;
          } else {
            mergedItems.push({ ...item });
          }
        }
      }
      
      const updateRes = await fetch(`/api/crates/${mergeToCrateId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ items: mergedItems }),
      });
      
      if (!updateRes.ok) throw new Error('Failed to update target crate');
      
      for (const sourceCrate of sourceCrates) {
        await fetch(`/api/crates/${sourceCrate.id}`, { method: 'DELETE', credentials: 'include' });
      }
      
      queryClient.invalidateQueries({ queryKey: ['crates'] });
      queryClient.invalidateQueries({ queryKey: ['/api/crates'] });
      toast.success(`Merged ${sourceCrates.length} crate(s) into "${targetCrate.name}"`);
      setSelectedCrates([]);
      setIsMergeCrateDialogOpen(false);
      setMergeToCrateId('');
    } catch (error) {
      console.error('Failed to merge crates:', error);
      toast.error('Failed to merge crates');
    } finally {
      setIsMerging(false);
    }
  };

