                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      setIsGoogleMerchantSyncing(true);
                      
                      const productCodes = selectedProducts
                        .map(id => productList.find(p => p.id === id)?.productCode)
                        .filter((code): code is string => !!code);
                      
                      if (productCodes.length === 0) {
                        toast.error("No valid product codes selected");
                        setIsGoogleMerchantSyncing(false);
                        return;
                      }
                      
                      fetch('/api/google-merchant/sync', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        credentials: 'include',
                        body: JSON.stringify({ productCodes })
                      })
                        .then(res => res.json().then(data => ({ ok: res.ok, data })))
                        .then(({ ok, data }) => {
                          if (!ok) {
                            toast.error(data.error || "Failed to sync products to Google Merchant");
                          } else {
                            setGoogleMerchantSyncResults({ total: data.total, successful: data.successful, failed: data.failed, results: data.results || [] }); setShowSyncResultsDialog(true); if (data.successful === 0 && data.failed > 0) { toast.error(`Sync failed for all ${data.total} products`); } else if (data.failed > 0) { toast.warning(`Synced ${data.successful} of ${data.total} products`); } else { toast.success(`Synced ${data.successful} of ${data.total} products to Google Merchant`); }
                          }
                        })
                        .catch(err => {
                          console.error("Sync fetch error:", err);
                          toast.error("Failed to connect to sync service");
                        })
                        .finally(() => {
                          setIsGoogleMerchantSyncing(false);
                        });
                    }}
                    disabled={isGoogleMerchantSyncing || selectedProducts.length === 0}
                    data-testid="button-google-merchant-sync"
                  >
                    {isGoogleMerchantSyncing ? (
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : (
                      <Globe className="w-4 h-4 mr-2" />
                    )}
                    Sync to Google
                  </Button>

