                        <SelectContent>
                          <SelectItem value="tiny">Tiny (10px)</SelectItem>
                          <SelectItem value="small">Small (12px)</SelectItem>
                          <SelectItem value="medium">Medium (14px)</SelectItem>
                          <SelectItem value="large">Large (16px)</SelectItem>
                        </SelectContent>
