      {/* Node/Crate Status Change Confirmation Dialog */}
      <AlertDialog open={!!pendingNodeSave} onOpenChange={(open) => !open && setPendingNodeSave(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirm Changes?</AlertDialogTitle>
            <AlertDialogDescription>
              {(() => {
                const nodeStatusChanged = pendingNodeSave?.status !== originalNodeStatus;
                const activatingCrates = Object.entries(pendingAssignmentStatuses).filter(
                  ([id, status]) => status === 'active' && originalAssignmentStatuses[id] === 'inactive'
                ).length;
                const deactivatingCrates = Object.entries(pendingAssignmentStatuses).filter(
                  ([id, status]) => status === 'inactive' && originalAssignmentStatuses[id] === 'active'
                ).length;
                
                const parts: string[] = [];
                if (nodeStatusChanged && pendingNodeSave?.status === 'active') {
                  parts.push('This node will become visible to customers.');
                } else if (nodeStatusChanged && pendingNodeSave?.status === 'inactive') {
                  parts.push('This node will be hidden from customers.');
                }
                if (activatingCrates > 0) {
                  parts.push(`${activatingCrates} crate(s) will be activated.`);
                }
                if (deactivatingCrates > 0) {
                  parts.push(`${deactivatingCrates} crate(s) will be deactivated.`);
                }
                return parts.join(' ') + ' Are you sure?';
              })()}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => {
              if (managingNode && originalNodeStatus) {
                setManagingNode({ ...managingNode, status: originalNodeStatus as 'active' | 'inactive' });
              }
              setPendingAssignmentStatuses({...originalAssignmentStatuses});
              setPendingNodeSave(null);
            }}>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={async () => {
                if (!pendingNodeSave) return;
                await handleUpdateNode(pendingNodeSave);
                for (const [assignmentId, newStatus] of Object.entries(pendingAssignmentStatuses)) {
                  if (newStatus !== originalAssignmentStatuses[assignmentId]) {
                    await fetch(`/api/crate-assignments/${assignmentId}/status`, {
                      method: 'PATCH',
                      headers: { 'Content-Type': 'application/json' },
                      body: JSON.stringify({ status: newStatus }),
                    });
                  }
                }
                queryClient.invalidateQueries({ queryKey: ['crate-assignments'] });
                setOriginalNodeStatus(pendingNodeSave.status);
                setIsManageNodeOpen(false);
                setManagingNode(null);
                setPendingNodeSave(null);
              }}
            >
              Confirm Changes
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
      
